_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000


def _xb(a, b):
    return bytes(x ^ y for x, y in zip(a, b))


def _runtime_key():
    return _xb(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))


def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]


def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()


def _open_cell(blob_text, r, c):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(f"stack-heap-bingo:cell:{r},{c}")
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        return _js.loads(_zl.decompress(_xb(ct, _stream(key, len(ct)))).decode())
    except Exception:
        return None


def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)


def _decrypt_line(blob_hex, answers):
    blob = bytes.fromhex(blob_hex)
    key = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return _xb(ct, _stream(key, len(ct))).decode()


def _hr():
    print("  " + "-" * 58)


def _banner(t):
    print()
    _hr()
    print(f"  {t}")
    _hr()


def _show_passphrase(p):
    print()
    _hr()
    print(f"  Passphrase: {p}")
    _hr()
    print()


ROWS = list("ABCDE")
COLS = list("12345")


class ActivityEngine:
    '''Core bingo check/passphrase logic; importable without a TTY.'''

    slug = "stack-heap-bingo"
    title = "Stack / Heap Bingo"

    def __init__(self):
        self.correct = [[False] * 5 for _ in range(5)]

    def categories(self):
        '''Return the numbered classification choices shown for every cell.'''
        return CATEGORIES

    def cell(self, r, c):
        '''Return the public (code, asks, note) dict for grid cell (r, c).'''
        return GRID[r][c]

    def check(self, r, c, raw):
        '''Check a 1-based category answer for cell (r, c); return {correct, correct_category, explanation}.'''
        secret = _open_cell(CELL_BLOBS[r][c], r, c)
        if secret is None:
            print("  [error] Could not open cell data.")
            sys.exit(1)
        correct = raw == secret["answer"]
        if correct:
            self.correct[r][c] = True
        return {
            "correct": correct,
            "correct_category": CATEGORIES[int(secret["answer"]) - 1],
            "explanation": secret.get("explanation", ""),
        }

    def bingo_line(self):
        '''Return (line_index, coords) for the first fully-correct line, or (None, None).'''
        for idx, line in enumerate(WINNING_LINES):
            if all(self.correct[r][c] for r, c in line):
                return idx, line
        return None, None

    def passphrase(self, line_idx, line):
        '''Return the passphrase unlocked by completing the given winning line.'''
        answers = [_open_cell(CELL_BLOBS[r][c], r, c)["answer"] for r, c in line]
        return _decrypt_line(LINE_BLOBS[line_idx], answers)


ENGINE = ActivityEngine()


def _render_grid():
    print()
    print("        1    2    3    4    5")
    for ri, row_label in enumerate(ROWS):
        marks = ["[X]" if ENGINE.correct[ri][ci] else "[ ]" for ci in range(5)]
        print(f"  {row_label}    " + "  ".join(marks))
    print()


def main():
    _banner(CATEGORIES[0].split("/")[0].strip().upper() + "/HEAP BINGO")
    print()
    print("  Classify each C++ variable. For each cell, choose:")
    print()
    for i, cat in enumerate(ENGINE.categories(), 1):
        print(f"    {i}. {cat}")
    print()
    print("  Complete any row, column, or diagonal to unlock the passphrase.")
    print()
    input("  Press Enter to begin...")

    while True:
        _render_grid()
        remaining = [(ROWS[r], COLS[c]) for r in range(5) for c in range(5) if not ENGINE.correct[r][c]]
        if not remaining:
            print("  All 25 cells answered correctly!")
            break

        raw = input("  Enter a cell (e.g. A1) or Q to quit: ").strip().upper()
        if raw in ("Q", "QUIT", "EXIT"):
            sys.exit(0)
        if len(raw) != 2 or raw[0] not in ROWS or raw[1] not in COLS:
            print("  Enter a letter A-E and a digit 1-5, like B3.")
            continue
        ri, ci = ROWS.index(raw[0]), COLS.index(raw[1])
        if ENGINE.correct[ri][ci]:
            print(f"  {raw} is already marked. Pick a different cell.")
            continue

        cell = ENGINE.cell(ri, ci)
        print()
        print(f"  Cell {raw} -- what is: {cell['asks']}?")
        if cell.get("note"):
            print(f"  ({cell['note']})")
        print()
        for line in cell["code"].split("\n"):
            print(f"    {line}")
        print()
        for i, cat in enumerate(ENGINE.categories(), 1):
            print(f"    {i}. {cat}")
        print()

        while True:
            ans = input("  Your answer (1-4): ").strip()
            if ans in ("1", "2", "3", "4"):
                break
            print("  Enter 1, 2, 3, or 4.")

        result = ENGINE.check(ri, ci, ans)
        if result["correct"]:
            if result["explanation"]:
                print(f"  Correct! {result['explanation']}")
            else:
                print("  Correct!")
            line_idx, bingo_line = ENGINE.bingo_line()
            if bingo_line is not None:
                phrase = ENGINE.passphrase(line_idx, bingo_line)
                labels = " ".join(ROWS[r] + COLS[c] for r, c in bingo_line)
                print()
                print(f"  BINGO! Completed line: {labels}")
                if phrase:
                    _show_passphrase(phrase)
                    return
                else:
                    print("  [error] Decryption failed -- contact instructor.")
                    sys.exit(1)
        else:
            print(f"  Not quite. The correct classification is: {result['correct_category']}")
            if result["explanation"]:
                print(f"  {result['explanation']}")
            print("  Try a different cell.")


if __name__ == "__main__":
    main()
